#!/bin/sh
# Generated by `harness eval bootstrap` — PROJECT-SPECIFIC grader SKELETON.
# Gates the release-to-content engine's definition-of-done: blocks any release where the four LangGraph graphs, the three human approval gates, evidence redaction-before-persistence, claim-to-evidence provenance, and canonical repo skills are missing or where content can be generated without an approved feature manifest.
# Exit 0 = pass, non-zero = fail. Fill the `# TODO` checks against the
# implemented code, then flip the eval's failure→"block-change" to enforce.
# Project acceptance gate — Release-to-Content Engine.
# Encodes the spec's core principle: never generate content directly from raw
# diffs; build an approved, redacted, evidence-backed manifest first, then
# generate content with claim-level provenance behind human approval gates.
# Exit 0 = PASS, non-zero = FAIL. Prints a one-line reason.
set -u

fail() { echo "FAIL: $1"; exit 1; }

# --- locate project root -------------------------------------------------
ROOT="${1:-.}"
cd "$ROOT" 2>/dev/null || fail "cannot enter project root '$ROOT'"

# --- pick a search tool (ripgrep preferred, grep fallback) ---------------
if command -v rg >/dev/null 2>&1; then
  search() { rg -q -i "$1" -- ${2:-.}; }
else
  search() { grep -R -q -i -- "$1" ${2:-.}; }
fi

# =========================================================================
# 1. Canonical skills live in the repo as skills/**/SKILL.md (spec §0, §1.9)
# =========================================================================
if ! find skills -type f -name 'SKILL.md' 2>/dev/null | grep -q .; then
  fail "no canonical skills found (expected skills/**/SKILL.md)"
fi

# =========================================================================
# 2. The four LangGraph graphs must exist (spec §5.1)
# =========================================================================
for g in release_intelligence_graph content_generation_graph media_generation_graph skill_learning_graph; do
  search "$g" || fail "missing required graph: $g"
done

# =========================================================================
# 3. Three human approval gates as LangGraph interrupts (spec §5.6)
#    Gate #1 feature manifest, Gate #2 artifacts, Gate #3 skill revision.
# =========================================================================
search "approve_feature_manifest" || fail "gate #1 (feature manifest approval) not found"
search "approve_artifacts"        || fail "gate #2 (artifact approval) not found"
search "approve_skill_candidate"  || fail "gate #3 (skill revision approval) not found"
# Gates must be real interrupts, not stubs/auto-approvals.
if command -v rg >/dev/null 2>&1; then
  rg -q -i 'interrupt' || fail "approval gates present but no LangGraph interrupt() usage found"
else
  grep -R -q -i 'interrupt' . || fail "approval gates present but no LangGraph interrupt() usage found"
fi

# =========================================================================
# 4. Redaction MUST precede persistence/LLM (spec §4, §5.2 redact->persist)
# =========================================================================
search "redact_evidence" || fail "no redact_evidence step (evidence must be redacted before persistence/LLM)"
search "persist_evidence" || fail "no persist_evidence step"

# =========================================================================
# 5. Claim-level provenance: every claim links to evidence (spec §1.7, §5.3)
# =========================================================================
search "extract_claims"          || fail "no claim extraction step"
search "link_claims_to_evidence" || fail "claims are not linked to evidence (provenance missing)"

# =========================================================================
# 6. Safety: deterministic policy checks + Bedrock Guardrails (spec §5.3)
# =========================================================================
search "run_deterministic_policy_checks" || fail "deterministic policy checks missing"
search -i "guardrail" || fail "Bedrock Guardrails integration not found"

# =========================================================================
# 7. BEHAVIORAL ACCEPTANCE — requires running code. Skeleton: fail loudly.
# =========================================================================

# 7a. Content generation must REFUSE to run without an approved feature
#     manifest (the central anti-requirement: no diff->content shortcut).
# TODO: invoke content_generation_graph with an unapproved/empty manifest and
#       assert it halts at gate #1 / errors instead of emitting artifacts.
#       e.g. python -m engine.test_acceptance --no-approval should exit non-zero
echo "TODO: assert content generation blocks without an approved feature manifest"
exit 1

# 7b. Every generated artifact claim must resolve to >=1 evidence_id.
# TODO: after a sample run, query produced artifacts (Aurora/JSON) and assert
#       no claim has an empty evidence reference set, e.g. with jq:
#       jq -e 'all(.claims[]; (.evidence_ids|length) > 0)' artifacts.json
# echo "TODO: assert no claim lacks evidence provenance"; exit 1

# 7c. Approved skill revision replaces repo SKILL.md and records commit SHA in
#     Aurora (spec §0, §5.5 update_repo_skill_file -> mark_candidate_promoted).
# TODO: simulate gate #3 approval and assert the target skills/**/SKILL.md is
#       rewritten AND a promotion row with a commit SHA is persisted.
# echo "TODO: assert approved skill promotion rewrites SKILL.md + records SHA"; exit 1

echo "PASS: project acceptance invariants satisfied"
exit 0

